import{_ as a,o as t,c as o,ai as i}from"./chunks/framework.B3x_xFnx.js";const p=JSON.parse('{"title":"Frequently Asked Questions","description":"","frontmatter":{},"headers":[],"relativePath":"ForUsers/faq.md","filePath":"ForUsers/faq.md"}'),r={name:"ForUsers/faq.md"};function s(n,e,l,d,h,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to “Frequently Asked Questions”">​</a></h1><h2 id="what-is-the-aim-of-pixelos" tabindex="-1">What is the aim of PixelOS? <a class="header-anchor" href="#what-is-the-aim-of-pixelos" aria-label="Permalink to “What is the aim of PixelOS?”">​</a></h2><p>To provide an experience similar to Google Pixel phones with numerous performance enhancements and a small amount of useful additional features.</p><h2 id="is-this-a-pixel-gsi-port" tabindex="-1">Is this a Pixel GSI/Port? <a class="header-anchor" href="#is-this-a-pixel-gsi-port" aria-label="Permalink to “Is this a Pixel GSI/Port?”">​</a></h2><p>No, this a source-built custom Android ROM [just like LineageOS].</p><h2 id="how-do-i-flash-it-on-my-device" tabindex="-1">How do I flash it on my device? <a class="header-anchor" href="#how-do-i-flash-it-on-my-device" aria-label="Permalink to “How do I flash it on my device?”">​</a></h2><p>Head over to the <a href="https://pixelos.net/download" target="_blank" rel="noreferrer">download page</a> for your device, you should find instructions for your device there. [Note: Instructions may not appear for few devices, ask your maintainer to add it]</p><h2 id="can-i-get-all-features-of-google-pixel-devices-on-pixelos" tabindex="-1">Can I get all features of Google Pixel devices on PixelOS? <a class="header-anchor" href="#can-i-get-all-features-of-google-pixel-devices-on-pixelos" aria-label="Permalink to “Can I get all features of Google Pixel devices on PixelOS?”">​</a></h2><p>No, it is practically not possible. Some features need hardware support and have different other requirements.</p><h2 id="why-is-the-quick-settings-black-in-light-mode" tabindex="-1">Why is the Quick Settings black in light mode? <a class="header-anchor" href="#why-is-the-quick-settings-black-in-light-mode" aria-label="Permalink to “Why is the Quick Settings black in light mode?”">​</a></h2><p>With the aim of the project being to provide a similar experience in look and feel to a Google Pixel device, the quick settings will always remain black in light and dark theme the same way it does on Pixel devices.</p><h2 id="when-is-the-next-update" tabindex="-1">When is the next update? <a class="header-anchor" href="#when-is-the-next-update" aria-label="Permalink to “When is the next update?”">​</a></h2><p>PixelOS is free to use and open-source. None of the maintainers are obligated to release updates whenever you want them to, and you are not entitled to them. <strong>Be patient; updates will be released when they are ready.</strong></p><div class="danger custom-block"><p class="custom-block-title">Asking for ETAs</p><p>Repeatedly asking for updates (&quot;ETAs&quot;) through the use of euphemisms in the community, such as &quot;Is there an update coming soon?&quot; will not be tolerated.</p></div><h2 id="how-to-report-bugs" tabindex="-1">How to report bugs? <a class="header-anchor" href="#how-to-report-bugs" aria-label="Permalink to “How to report bugs?”">​</a></h2><p><a href="./../guides/BugReport.html">Refer to this guide</a> to learn how to take proper logs. Then send these logs over to your maintainer through our community.</p><h2 id="should-i-clean-flash-to-upgrade-to-a-newer-version" tabindex="-1">Should I clean flash to upgrade to a newer version? <a class="header-anchor" href="#should-i-clean-flash-to-upgrade-to-a-newer-version" aria-label="Permalink to “Should I clean flash to upgrade to a newer version?”">​</a></h2><p>If a clean flash is necessary, it will be mentioned on either the release post on Telegram or in the changelog section of the device page on the website. If a clean flash isn&#39;t mentioned as being necessary, a dirty flash should be fine.</p><h2 id="does-pixelos-give-good-battery-life" tabindex="-1">Does PixelOS give good battery life? <a class="header-anchor" href="#does-pixelos-give-good-battery-life" aria-label="Permalink to “Does PixelOS give good battery life?”">​</a></h2><p>We can&#39;t give estimates battery life or SOT (Screen On Time) as it is very subjective and depends on a lot of variables from obvious things like Screen Brightness to things which you probably did not know could affect your battery like your network/Wi-Fi coverage.</p><h2 id="when-pixelos-for-my-xyz-device" tabindex="-1">When PixelOS for my XYZ device? <a class="header-anchor" href="#when-pixelos-for-my-xyz-device" aria-label="Permalink to “When PixelOS for my XYZ device?”">​</a></h2><p>Head over to our Official Downloads Page, if you find your device there, then it has/had an official PixelOS build, if not, it does not. If you really want to try out PixelOS for your device, ask a developer/maintainer to build it for you, otherwise you can learn how to build ROMs and do it yourself.</p><h2 id="can-i-pm-you" tabindex="-1">Can I PM you? <a class="header-anchor" href="#can-i-pm-you" aria-label="Permalink to “Can I PM you?”">​</a></h2><p>No.</p><h2 id="why-we-use-cat-pics-everywhere-seriously" tabindex="-1">Why we use cat pics everywhere? <a href="https://t.me/pixeloschat/134098" target="_blank" rel="noreferrer">Seriously...</a> <a class="header-anchor" href="#why-we-use-cat-pics-everywhere-seriously" aria-label="Permalink to “Why we use cat pics everywhere? Seriously...”">​</a></h2><p>Because they are cute and adorable.</p><h2 id="will-we-add-x-feature" tabindex="-1">Will we add x feature? <a class="header-anchor" href="#will-we-add-x-feature" aria-label="Permalink to “Will we add x feature?”">​</a></h2><p>We don&#39;t accept feature requests.</p><h2 id="dfe" tabindex="-1">DFE <a class="header-anchor" href="#dfe" aria-label="Permalink to “DFE”">​</a></h2><p>DFE is not recommended or supported on PixelOS. Android expects the system to be encrypted, so decrypting it introduces all manner of strange behaviour, so we don&#39;t accept bug reports from decrypted users. Use at your own risk and do not expect support.</p><p>Credit to SebaUbuntu for this explanation as to why we don&#39;t support it. For further reading you can check out <a href="https://kubersharma001.com/reasons-to-stay-encrypted-on-android-and-the-risks-otherwise" target="_blank" rel="noreferrer">this</a> blog post.</p><p>Little reminder on why you should not flash DFEs</p><ul><li><p>Userdata is NOT a sensitive partition, you can do whatever you want with it, but you&#39;ll never do damages, and also encryption process is 100% secure and there are 0 risks of bricking (you can actually have more issues if you flash DFE, will explain later) &quot;But I need to format data everytime I flash a new ROM!&quot; Stop flashing multiple ROMs, you should daily drive one, not ruining your EMMC/UFS by flashing 1747858 ROMs Also, if ROM maintainers recommends to not use DFE, don&#39;t use it Being decrypted or encrypted actually changes how Android handles booting TL;DR Basically Android has 2 phases during boot: pre-decryption and after-decryption If you disable encryption, there can be race conditions where stuff expects to start only after data has been decrypted but it starts together with core services, creating issues One example is in X00H and X00I, where if you run decrypted will break camera completely</p></li><li><p>&quot;data encryption on custom ROMs is useless&quot;: It&#39;s actually even more useful! If your device gets stolen, no one will be able to access your data, and the only way is to format data</p></li></ul><p>Conclusion: Unless you have a good reason (and there are none), do not never ever flash DFEs We support DFE in PixelOS, if you report a bug and you&#39;re decrypted your issue will be happily discarded</p>',34)])])}const f=a(r,[["render",s]]);export{p as __pageData,f as default};
